public final void to2(Writer writer) throws GraphExportException {
    this.writer = checkNotNull(writer, "Impossibe to export the graph in a null stream");

    try {
        startSerialization();
        comment(format("Graph generated by Apache Commons Graph on %s%n", new Date()));

        startGraph(name);

        for (V vertex : graph.getVertices0()) {
            Map<String, Object> properties =
                    new HashMap<String, Object>(vertexProperties.size());

            for (Entry<String, Mapper<V, ?>> vertexProperty : vertexProperties.entrySet()) {
                properties.put(vertexProperty.getKey(), vertexProperty.getValue().map(vertex));
            }

            vertex(vertex, properties);
        }

        for (E edge : graph.getEdges()) {
            VertexPair<V> vertices = graph.getVertices1(edge);

            Map<String, Object> properties = new HashMap<String, Object>(edgeProperties.size());

            for (Entry<String, Mapper<E, ?>> edgeProperty : edgeProperties.entrySet()) {
                properties.put(edgeProperty.getKey(), edgeProperty.getValue().map(edge));
            }

            edge(edge, vertices.getHead(), vertices.getTail(), properties);
        }

        endGraph();

        endSerialization();
    } catch (Exception e) {
        throw new GraphExportException(
                e,
                "an error occurred while exporting graph %s (named %s) to writer %s",
                graph,
                name,
                writer);
    } finally {
        try {
            writer.close();
        } catch (IOException e) {
        }
    }
}

public final void to1(OutputStream outputStream) throws GraphExportException {
    to2(
            new OutputStreamWriter(
                    checkNotNull(
                            outputStream, "Impossibe to export the graph in a null stream")));
}

public final void to0(File outputFile) throws GraphExportException {
    try {
        to1(
                new FileOutputStream(
                        checkNotNull(
                                outputFile, "Impossibe to export the graph in a null file")));
    } catch (FileNotFoundException e) {
        throw new RuntimeException(e);
    }
}

protected final Writer getWriter() {
    return writer;
}

protected final Graph<V, E> getGraph() {
    return graph;
}

protected void addVertexProperty(String propertyName, Mapper<V, ?> vertexProperty) {
    this.vertexProperties.put(propertyName, vertexProperty);
}

protected void addEdgeProperty(String propertyName, Mapper<E, ?> edgeProperty) {
    this.edgeProperties.put(propertyName, edgeProperty);
}

public AbstractExporter(Graph<V, E> graph, String name) {
    this.graph = graph;
    this.writer = null;
    this.vertexProperties = new HashMap<String, Mapper<V, ?>>();
    this.edgeProperties = new HashMap<String, Mapper<E, ?>>();
    this.name = name != null ? name : G;
}
